setupCurrentBackupRegion.query:
#graphql
  mutation BackupRegionUpdateRestore {
    backupRegionUpdate(region: { countryCode: CA }) {

  backupRegion {
    __typename
    id
    name
    ... on MarketRegionCountry {
      code
    }
  }
